#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define THREADS 256

inline void storeComponents(__global float *d_r, __global float *d_g, __global float *d_b, float r, float g, float b, int pos)
{
    d_r[pos] = (r/255.0f) - 0.5f;
    d_g[pos] = (g/255.0f) - 0.5f;
    d_b[pos] = (b/255.0f) - 0.5f;
}

inline void storeComponents(__global int *d_r, __global int *d_g, __global int *d_b, int r, int g, int b, int pos)
{
    d_r[pos] = r - 128;
    d_g[pos] = g - 128;
    d_b[pos] = b - 128;
}

inline void storeComponent(__global float *d_c, float c, int pos)
{
    d_c[pos] = (c/255.0f) - 0.5f;
}

inline void storeComponent(__global int *d_c, int c, int pos)
{
    d_c[pos] = c - 128;
}

__kernel void c_CopySrcToComponents(__global float *d_r, __global float *d_g, __global float *d_b, 
                                   __global uchar *d_src, int pixels)
{
    int x = get_local_id(0);
    int gX = get_group_id(0) * get_local_size(0);

    __local uchar sData[THREADS*3];

    if ((THREADS*3) > (x*4)) {
        __global float *s = (__global float *)d_src;
        __local float *d = (__local float *)sData;
        d[x] = s[((gX*3)>>2) + x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float r, g, b;

    int offset = x*3;
    r = (float)(sData[offset]);
    g = (float)(sData[offset+1]);
    b = (float)(sData[offset+2]);

    int globalOutputPosition = gX + x;
    if (globalOutputPosition < pixels) {
        storeComponents(d_r, d_g, d_b, r, g, b, globalOutputPosition);
    }
}

